histrix.customScript:
	$('div[instance="[__instance__]"]').on('change','[campo="grabar"] :input', function(){
		$row = $(this).closest('tr');
		$table = $row.closest('table');

		var items=[];
		$('tbody tr td:nth-child(6)', $table).each( function(){
			$mirow = $(this).closest('tr');
			var graba  = $('[campo="grabar"] :input', $mirow ).is(':checked');
			var valor  = $('[campo="coddem"]', $mirow ).attr('valor');
			if (graba) {
			items.push( valor );
			}
		});
		console.log(items);
		$masterrow = $row.closest('td').closest('tr');
		$(':input[name="demeritos"]', $masterrow ).val(items);
	});

	$('div[instance="[__instance__]"]').on('change focus',':input[name="ingresan"], :input[name="marcar"]', function(){
		$('div[instance="[__instance__]"] [campo="grabar"] :input').change();
	});

	$('div[instance="[__instance__]"]').on('focus', ':input', function(){
		$("input.date:enabled").datepicker();

	});



    $('div[instance="[__instance__]"]').on('change', '[name="vencimiento"]', function() {

        var $row = $(this).closest('[o]');
        var dias_fifo = parseInt(($('[name="dias_fifo"]', $row).val() || 0));
		if (dias_fifo != 0) {
			var fecha = $(this).val();
			var recepcion = straFecha($('[instance="[__instance__]"] [name="movfec__1"]').val() );
			var d = straFecha(fecha) ; 

			d.setDate(d.getDate() - dias_fifo); 
			//$('[name="limite_fifo"]', $row).val(d.toLocaleDateString('en-GB'));

			if (d <= recepcion) {
				alert('FUERA DE FECHA DE VENCIMIENTO');
			}

			if (fecha != '') {
				$('[name="ingresan"], [name="marcar"], [name="Unidades"]' , $row).removeAttr('disabled').removeAttr('readonly');
			}
			if (fecha == '') {
				$('[name="ingresan"], [name="marcar"], [name="Unidades"]', $row).removeAttr('disabled').removeAttr('readonly').val('');
			}			
		}


    });
function esperarFilasYAplicar() {
    loger('espero a que se llene');
    const interval = setInterval(function () {
        const $tabla = $('[instance="[__instance__]"] table[xml="cps_detalle_grid_rec.xml"]');
        const $filas = $tabla.find("tbody tr");
        const $marcar = $tabla.find('[name="marcar"]');

        loger("filas detectadas: " + $filas.length + ", marcar: " + $marcar.length);

        if ($filas.length > 0 && $marcar.length > 0) {
            clearInterval(interval);
            loger('se lleno con filas y marcar');

            $tabla.find('[campo="habilita_inspec"]').each(function (index, element) {
                loger('encuentro habilitado');
                const $habil = $(element);
				var valor =  $habil.attr('valor');
                loger('valor habilitado ' + $habil.attr('valor'));

                const $tr = $habil.closest('tr');
				if (valor == 'true') {
					$('[name="marcar"], [name="ingresan"] , [name="Unidades"] ', $tr).prop("disabled", true).attr("disabled", "disabled");

				} else {
					$('[name="marcar"], [name="ingresan"] , [name="Unidades"] ', $tr).prop("disabled", false).removeAttr("disabled");

				}

            });
        }
    }, 500);
};


esperarFilasYAplicar();
